   248→    }
   249→    case 'EncodeNode': {
   250→      const en = node as EncodeNode;
   251→      return `${indent}EncodeNode: ${en.inputVar} -> ${en.outputVar}`;
   252→    }
   253→    case 'PathNode': {
   254→      const pn = node as PathNode;
   255→      return `${indent}PathNode(${pn.pathType}): ${pn.inputVar} -> ${pn.outputVar}`;
   256→    }
   257→    case 'WeightNode': {
   258→      const wn = node as WeightNode;
   259→      const weights = wn.weights
   260→        ? ` [α=${wn.weights.alpha.toFixed(2)}, β=${wn.weights.beta.toFixed(2)}, γ=${wn.weights.gamma.toFixed(2)}]`
   261→        : '';
   262→      return `${indent}WeightNode: ${wn.inputVar}${weights}`;
   263→    }
   264→    case 'EnsembleNode': {
   265→      const ens = node as EnsembleNode;
   266→      return `${indent}EnsembleNode: (${ens.pathVars.join(', ')}) with ${ens.weightsVar} -> ${ens.outputVar}`;
   267→    }
   268→    case 'CritiqueNode': {
   269→      const cn = node as CritiqueNode;
   270→      return `${indent}CritiqueNode: ${cn.inputVar} -> ${cn.outputVar}`;
   271→    }
   272→    case 'SampleNode': {
   273→      const sn = node as SampleNode;
   274→      return `${indent}SampleNode: ${sn.inputVar} -> ${sn.outputVar}`;
   275→    }
   276→    case 'DetokenizeNode': {
   277→      const dn = node as DetokenizeNode;
   278→      return `${indent}DetokenizeNode: ${dn.inputVar} -> ${dn.outputVar}`;
   279→    }
   280→    default:
   281→      return `${indent}UnknownNode`;
   282→  }
   283→}
