  // =========================================================================

  private matrixVectorMultiply(matrix: Matrix, vector: Vector): Vector {
    const result: Vector = [];
    for (let i = 0; i < matrix.length; i++) {
      let sum = 0;
      for (let j = 0; j < vector.length && j < matrix[i].length; j++) {
        sum += matrix[i][j] * vector[j];
      }
      result.push(sum);
    }
    return result;
  }
});

