    );
    const vec = new Array(10).fill(1e-38);

    const clipped = NumericalStabilityOptimizer.clipValues(vec, -1e10, 1e10);
    expect(clipped.every(x => !isNaN(x) && !isInfinite(x))).toBe(true);
  });

